// S/ AgentOS Kernel v0.2.0 — Command Gateway auth + envelope validation
const incoming = $input.first().json || {};
const body = incoming.body || {};
const headers = incoming.headers || {};

function getHeader(name) {
  const target = String(name).toLowerCase();
  for (const [key, value] of Object.entries(headers)) {
    if (String(key).toLowerCase() === target) {
      return Array.isArray(value) ? value[0] : value;
    }
  }
  return "";
}

function cleanId(prefix) {
  const raw = `${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
  return `${prefix}_${raw}`;
}

const authHeader = String(getHeader("authorization") || "");
const bearerToken = authHeader.replace(/^Bearer\s+/i, "").trim();
const xAgentOSKey = String(getHeader("x-agentos-key") || "").trim();

const expectedKey = process.env.S_AGENTOS_OPERATOR_KEY || process.env.S_AGENTOS_API_TOKEN || "";
const providedToken = xAgentOSKey || bearerToken;
const authValid = Boolean(expectedKey && providedToken && providedToken === expectedKey);

const allowedActions = [
  "health_check", "create_agent", "execute_task", "evaluate_agent", "evolve_agent",
  "registry_sync", "telemetry_log", "list_agents", "get_agent", "update_agent_status"
];
const allowedPriorities = ["low", "normal", "medium", "high", "urgent", "critical"];
const allowedRunModes = ["draft", "dry_run", "read_only", "live"];
const allowedApprovalStatuses = ["not_required", "pending", "approved", "rejected", "expired"];

const action = body.action;
const objective = typeof body.objective === "string" ? body.objective.trim() : "";
const command_id = body.command_id || cleanId("cmd");
const trace_id = body.trace_id || cleanId("trace");
const idempotency_key = body.idempotency_key || null;
const requested_by = body.requested_by || "operator";
const priority = allowedPriorities.includes(body.priority) ? body.priority : "normal";
const run_mode = allowedRunModes.includes(body.run_mode) ? body.run_mode : "draft";
const approval_status = allowedApprovalStatuses.includes(body.approval_status) ? body.approval_status : "not_required";
const agent_id = body.agent_id || null;
const context = body.context && typeof body.context === "object" ? body.context : {};
const metadata = body.metadata && typeof body.metadata === "object" ? body.metadata : {};

const validationErrors = [];
if (!allowedActions.includes(action)) validationErrors.push("Unsupported or missing action");
if (!objective) validationErrors.push("objective is required");
if (body.command_id && !/^cmd_[A-Za-z0-9_\-]+$/.test(body.command_id)) validationErrors.push("command_id must start with cmd_");
if (body.trace_id && !/^trace_[A-Za-z0-9_\-]+$/.test(body.trace_id)) validationErrors.push("trace_id must start with trace_");
if (idempotency_key && String(idempotency_key).length > 128) validationErrors.push("idempotency_key max length is 128");

const writeActions = ["create_agent", "execute_task", "evaluate_agent", "evolve_agent", "registry_sync", "telemetry_log", "update_agent_status"];
const approvalRequired = run_mode === "live" && writeActions.includes(action);
const approvalAllowed = !approvalRequired || approval_status === "approved";
if (!approvalAllowed) validationErrors.push("live write actions require approval_status=approved");

return [{
  json: {
    ...incoming,
    body,
    headers,
    auth_method: xAgentOSKey ? "x-agentos-key" : (bearerToken ? "bearer" : "missing"),
    x_agentos_key: providedToken ? "[REDACTED]" : null,
    authValid,
    validationValid: validationErrors.length === 0,
    validationErrors,
    command: {
      command_id,
      trace_id,
      idempotency_key,
      action,
      objective,
      requested_by,
      priority,
      run_mode,
      approval_status,
      approval_required: approvalRequired,
      agent_id,
      context,
      metadata,
      kernel_version: "0.2.0"
    }
  }
}];

const j = $input.first().json || {};
return [{ json: {
  ok: false,
  error: "Unauthorized",
  message: "Missing or invalid S/ AgentOS operator key. Use X-AgentOS-Key or Authorization: Bearer.",
  code: 401,
  command_id: j.command?.command_id || null,
  trace_id: j.command?.trace_id || null,
  kernel_version: "0.2.0"
}}];

const j = $input.first().json || {};
return [{ json: {
  ok: false,
  error: "Validation Failed",
  message: (j.validationErrors || []).join("; "),
  code: 400,
  command_id: j.command?.command_id || null,
  trace_id: j.command?.trace_id || null,
  kernel_version: "0.2.0"
}}];

// S/ AgentOS Kernel v0.2.0 — safe command router.
// This gateway is intentionally safe-by-default. It routes and returns a normalized response.
// Consequential side effects should be implemented downstream after approval/idempotency persistence.
const j = $input.first().json || {};
const c = j.command || {};

const routeByAction = {
  health_check: "kernel_health",
  create_agent: "agent_registry",
  execute_task: "task_executor",
  evaluate_agent: "evaluation_engine",
  evolve_agent: "evolution_engine",
  registry_sync: "agent_registry",
  telemetry_log: "telemetry_logger",
  list_agents: "agent_registry",
  get_agent: "agent_registry",
  update_agent_status: "agent_registry"
};

const route = routeByAction[c.action] || "unsupported";

const safeModes = ["draft", "dry_run", "read_only"];
const side_effects_enabled = c.run_mode === "live" && c.approval_status === "approved";

let result = {};
if (c.action === "health_check") {
  result = {
    status: "healthy",
    mode: "command_gateway",
    provider_agnostic: true,
    supported_actions: Object.keys(routeByAction),
    side_effects_enabled: false
  };
} else {
  result = {
    accepted: true,
    planned_route: route,
    safe_mode: safeModes.includes(c.run_mode),
    side_effects_enabled,
    next_step: side_effects_enabled
      ? "Execute downstream workflow with persisted audit/idempotency checks."
      : "No live side effects. Return plan only until run_mode=live and approval_status=approved."
  };
}

return [{ json: {
  ok: true,
  system: "S/ AgentOS",
  kernel_version: "0.2.0",
  trace_id: c.trace_id,
  command_id: c.command_id,
  idempotency_key: c.idempotency_key,
  action: c.action,
  requested_by: c.requested_by,
  priority: c.priority,
  run_mode: c.run_mode,
  approval_status: c.approval_status,
  approval_required: c.approval_required,
  route,
  result
}}];
